do.example:
let n = 0;
do {
  console.log(n);
  n++;
} while (n < 3);

break.example:
for (let i = 0; i < 10; i++) {
  if (i === 3) break;
  console.log(i);
}

continue.example:
for (let i = 0; i < 5; i++) {
  if (i % 2 === 0) continue;
  console.log(i);
}

throw.example:
